function eventLoopDemo() {
  console.log('同步代码开始');

  // 宏任务
  setTimeout(() => {
    console.log('宏任务执行');
  }, 0);

  // 微任务
  Promise.resolve().then(() => {
    console.log('微任务执行');
  });

  console.log('同步代码结束');
  // 输出顺序：同步代码开始 -> 同步代码结束 -> 微任务执行 -> 宏任务执行
}
eventLoopDemo();
